window.jQuery = window.$ = window.jQuery || function jQuery(selector) {
  const nodes = typeof selector === "string" ? Array.from(document.querySelectorAll(selector)) : [selector];
  return {
    nodes,
    ready(fn) { if (document.readyState !== "loading") fn(); else document.addEventListener("DOMContentLoaded", fn); return this; },
    on(event, fn) { nodes.forEach((node) => node && node.addEventListener && node.addEventListener(event, fn)); return this; },
    hide() { nodes.forEach((node) => { if (node && node.style) node.style.display = "none"; }); return this; },
    show() { nodes.forEach((node) => { if (node && node.style) node.style.display = ""; }); return this; },
    html(value) { if (value === undefined) return nodes[0] ? nodes[0].innerHTML : ""; nodes.forEach((node) => { if (node) node.innerHTML = value; }); return this; }
  };
};
